1	type Quote = { premium: number };
2	type Item = { type: string; cursed?: boolean; enchantment?: number };
3	type QuoteInput = {
4	  customer?: { yearsWithMHPCO: number };
5	  firstInsurance?: boolean;
6	  followUp?: boolean;
7	  items: Item[];
8	};
9	
10	const PROCESSING_FEE = 5;
11	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
12	  sword: 100,
13	  staff: 80,
14	  amulet: 60,
15	  potion: 40,
16	  rune: 25,
17	  moonstone: 25,
18	};
19	const ALIKE_BLOCK_SIZE = 3;
20	const ALIKE_BLOCK_PREMIUM = 60;
21	const CURSE_SURCHARGE_RATE = 0.5;
22	const HIGH_ENCHANTMENT_THRESHOLD = 5;
23	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
24	const LOYALTY_YEARS_THRESHOLD = 2;
25	const LOYALTY_DISCOUNT_RATE = 0.2;
26	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
27	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
28	
29	const basePremiumFor = (item: Item): number => {
30	  const basePremium = BASE_PREMIUM_BY_TYPE[item.type];
31	  if (basePremium === undefined) {
32	    throw new Error(`Unknown item type: ${item.type}`);
33	  }
34	  return basePremium;
35	};
36	
37	const curseSurchargeRateFor = (item: Item): number =>
38	  item.cursed ? CURSE_SURCHARGE_RATE : 0;
39	
40	const enchantmentSurchargeRateFor = (item: Item): number =>
41	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
42	    ? HIGH_ENCHANTMENT_SURCHARGE_RATE
43	    : 0;
44	
45	const totalSurchargeRateFor = (item: Item): number =>
46	  curseSurchargeRateFor(item) + enchantmentSurchargeRateFor(item);
47	
48	const itemPremiumFor = (item: Item): number =>
49	  basePremiumFor(item) * (1 + totalSurchargeRateFor(item));
50	
51	const sumItemPremiums = (items: Item[]): number =>
52	  items.reduce((sum, item) => sum + itemPremiumFor(item), 0);
53	
54	const isAlikeBlock = (items: Item[]): boolean =>
55	  items.length === ALIKE_BLOCK_SIZE &&
56	  items.every((item) => item.type === items[0].type);
57	
58	const componentsPremium = (items: Item[]): number =>
59	  isAlikeBlock(items) ? ALIKE_BLOCK_PREMIUM : sumItemPremiums(items);
60	
61	const loyaltyDiscountRateFor = (input: QuoteInput): number =>
62	  (input.customer?.yearsWithMHPCO ?? 0) >= LOYALTY_YEARS_THRESHOLD
63	    ? LOYALTY_DISCOUNT_RATE
64	    : 0;
65	
66	const firstInsuranceSurchargeRateFor = (input: QuoteInput): number =>
67	  input.firstInsurance ? FIRST_INSURANCE_SURCHARGE_RATE : 0;
68	
69	const followUpDiscountRateFor = (input: QuoteInput): number =>
70	  input.followUp ? FOLLOW_UP_DISCOUNT_RATE : 0;
71	
72	const policyAdjustmentRateFor = (input: QuoteInput): number =>
73	  firstInsuranceSurchargeRateFor(input) -
74	  loyaltyDiscountRateFor(input) -
75	  followUpDiscountRateFor(input);
76	
77	export const quote = (input: QuoteInput): Quote => {
78	  const componentsTotal = componentsPremium(input.items);
79	  const policyTotal = componentsTotal + componentsTotal * policyAdjustmentRateFor(input);
80	  return { premium: Math.ceil(policyTotal + PROCESSING_FEE) };
81	};
82	
83	export const claim = (_input: unknown): unknown => ({ payout: 400, remainingCap: 1600 });
